 1→import { ViteDevServer, defineConfig } from 'vite';
 2→
 3→export function pluginWatchNodeModules(modules: string[]) {
 4→  const pattern = `/node_modules\\/(?!${modules.join('|')}).*/`;
 5→  return {
 6→    name: 'watch-node-modules',
 7→    configureServer: (server: ViteDevServer): void => {
 8→      server.watcher.options = {
 9→        ...server.watcher.options,
10→        ignored: [new RegExp(pattern), '**/.git/**'],
11→      };
12→    },
13→  };
14→}
15→
16→export default defineConfig({
17→  plugins: [pluginWatchNodeModules(['autk-map', 'autk-db'])],
18→  optimizeDeps: {
19→    exclude: ['autk-db', 'autk-map'],
20→  },
21→  server: {
22→    fs: {
23→      allow: ['..'],
24→    },
25→    cors: {
26→      origin: '*',
27→      allowedHeaders: 'Range, Content-Type, Authorization',
28→      exposedHeaders: 'Content-Range',
29→    },
30→  },
31→});

  1→import { SpatialDb } from 'autk-db';
  2→import { AutkMap, LayerType, MapEvent, ColorMapInterpolator } from 'autk-map';
  3→
  4→const statusEl = document.getElementById('loading-status')!;
  5→const overlay = document.getElementById('loading-overlay')!;
  6→
  7→function setStatus(msg: string) {
  8→  statusEl.textContent = msg;
  9→  console.log(`[status] ${msg}`);
 10→}
 11→
 12→async function main() {
 13→  try {
 14→    // ── 1. Initialize database ──────────────────────────────────────
 15→    setStatus('Initializing spatial database...');
 16→    const db = new SpatialDb();
 17→    await db.init();
 18→    console.log('SpatialDb initialized');
 19→
 20→    // ── 2. Load OSM layers for Manhattan Island ─────────────────────
 21→    setStatus('Loading OpenStreetMap data for Manhattan Island...');
 22→    await db.loadOsmFromOverpassApi({
 23→      queryArea: {
 24→        geocodeArea: 'New York',
 25→        areas: ['Manhattan Island'],
 26→      },
 27→      outputTableName: 'osm',
 28→      autoLoadLayers: {
 29→        coordinateFormat: 'EPSG:3395',
 30→        layers: ['surface', 'parks', 'water', 'roads', 'buildings'],
 31→        dropOsmTable: true,
 32→      },
 33→      onProgress: (phase) => {
 34→        console.log(`[OSM progress] ${phase}`);
 35→        setStatus(`OSM: ${phase}`);
 36→      },
 37→    });
 38→    console.log('OSM data loaded successfully');
 39→
 40→    const layerTables = db.getLayerTables();
 41→    console.log('Layer tables:', layerTables.map((l) => l.name));
 42→
 43→    // ── 3. Load subway station CSV ──────────────────────────────────
 44→    setStatus('Loading subway station data...');
 45→    await db.loadCsv({
 46→      csvFileUrl: 'http://localhost:5173/data/subway_manhattan_clean.csv',
 47→      outputTableName: 'subway_stations',
 48→      delimiter: ',',
 49→      geometryColumns: {
 50→        latColumnName: 'latitude',
 51→        longColumnName: 'longitude',
 52→        coordinateFormat: 'EPSG:3395',
 53→      },
 54→    });
 55→    console.log('Subway station CSV loaded');
 56→
 57→    // ── 4. Spatial join: count subway stations within 500m of each building ──
 58→    setStatus('Running spatial join (buildings ↔ subway stations, 500m)...');
 59→    await db.spatialJoin({
 60→      tableRootName: 'osm_buildings',
 61→      tableJoinName: 'subway_stations',
 62→      output: { type: 'MODIFY_ROOT' },
 63→      spatialPredicate: 'NEAR',
 64→      nearDistance: 500,
 65→      nearUseCentroid: true,
 66→      joinType: 'LEFT',
 67→      groupBy: {
 68→        selectColumns: [
 69→          {
 70→            tableName: 'subway_stations',
 71→            column: 'key',
 72→            aggregateFn: 'count',
 73→            aggregateFnResultColumnName: 'subway_count'
 74→          },
 75→        ],
 76→      },
 77→    });
 78→    console.log('Spatial join complete');
 79→
 80→    // ── 5. Initialize the 3D map ────────────────────────────────────
 81→    setStatus('Initializing 3D map renderer...');
 82→    const canvas = document.getElementById('map-canvas') as HTMLCanvasElement;
 83→    const map = new AutkMap(canvas, true);
 84→    await map.init();
 85→    console.log('AutkMap initialized');
 86→
 87→    // ── 6. Load all OSM layers into the map ─────────────────────────
 88→    setStatus('Loading layers into map...');
 89→    for (const layer of db.getLayerTables()) {
 90→      // Skip the subway_stations point layer from map rendering
 91→      if (layer.name === 'subway_stations') continue;
 92→
 93→      const geojson = await db.getLayer(layer.name);
 94→      const featureCount = geojson.features?.length ?? 0;
 95→      console.log(`Loading layer "${layer.name}" (type: ${layer.type}, features: ${featureCount})`);
 96→      map.loadGeoJsonLayer(layer.name, geojson, layer.type as LayerType);
 97→    }
 98→    console.log('All layers loaded into map');
 99→
100→    // ── 7. Apply thematic coloring to buildings ─────────────────────
101→    setStatus('Applying subway accessibility coloring...');
102→    const buildingsGeoJson = await db.getLayer('osm_buildings');
103→    console.log(`Buildings for thematic: ${buildingsGeoJson.features?.length ?? 0} features`);
104→
105→    map.updateRenderInfoProperty('osm_buildings', 'colorMapInterpolator', ColorMapInterpolator.SEQUENTIAL_REDS);
106→    map.updateRenderInfoProperty('osm_buildings', 'isColorMap', true);
107→    map.updateRenderInfoProperty('osm_buildings', 'colorMapLabels', ['0 stations', 'Max stations']);
108→
109→    map.updateGeoJsonLayerThematic(
110→      'osm_buildings',
111→      buildingsGeoJson,
112→      (feature) => {
113→        const sjoin = feature.properties?.sjoin;
114→        if (!sjoin) return 0;
115→        const countObj = sjoin.count;
116→        if (!countObj) return 0;
117→        return countObj.subway_count_norm ?? countObj.subway_count ?? 0;
118→      },
119→      true,
120→    );
121→    console.log('Thematic coloring applied to buildings');
122→
123→    // ── 8. Enable picking on all visible layers ─────────────────────
124→    setStatus('Enabling layer picking...');
125→    const pickableLayers = ['osm_surface', 'osm_parks', 'osm_water', 'osm_roads', 'osm_buildings'];
126→    for (const layerName of pickableLayers) {
127→      map.updateRenderInfoProperty(layerName, 'isPick', true);
128→      console.log(`Picking enabled for "${layerName}"`);
129→    }
130→
131→    map.mapEvents.addEventListener(MapEvent.PICK, (selectedIds: number[], layerId: string) => {
132→      if (selectedIds.length > 0) {
133→        console.log(`[PICK] Layer: "${layerId}", selected IDs:`, selectedIds);
134→      } else {
135→        console.log(`[PICK] Deselected on layer: "${layerId}"`);
136→      }
137→    });
138→    console.log('Pick event listener registered');
139→
140→    // ── 9. Start rendering ──────────────────────────────────────────
141→    map.draw();
142→    console.log('Render loop started');
143→
144→    // Hide the loading overlay
145→    overlay.style.display = 'none';
146→    setStatus('Done');
147→    console.log('Application fully loaded');
148→  } catch (err) {
149→    console.error('Application error:', err);
150→    setStatus(`Error: ${err instanceof Error ? err.message : String(err)}`);
151→  }
152→}
153→
154→main();
