  1→import { SpatialDb } from "autk-db";
  2→import { AutkMap, LayerType, ColorMapInterpolator, MapEvent } from "autk-map";
  3→import { GeojsonCompute } from "autk-compute";
  4→import type { Feature } from "geojson";
  5→
  6→function setPhase(text: string) {
  7→  const el = document.getElementById("phase");
  8→  if (el) el.textContent = text;
  9→  console.log(`[Phase] ${text}`);
 10→}
 11→
 12→async function main() {
 13→  const canvas = document.getElementById("map-canvas") as HTMLCanvasElement;
 14→
 15→  // ── 1. Initialize spatial database ──
 16→  setPhase("Initializing spatial database...");
 17→  const db = new SpatialDb();
 18→  await db.init();
 19→  console.log("SpatialDb initialized");
 20→
 21→  // ── 2. Initialize GPU compute ──
 22→  const gpuCompute = new GeojsonCompute();
 23→  console.log("GeojsonCompute initialized");
 24→
 25→  // ── 3. Load OSM data for Manhattan Island ──
 26→  setPhase("Loading OSM data for Manhattan Island...");
 27→  console.log("Fetching Overpass API for Manhattan Island...");
 28→
 29→  await db.loadOsmFromOverpassApi({
 30→    queryArea: {
 31→      geocodeArea: "New York",
 32→      areas: ["Manhattan Island"],
 33→    },
 34→    outputTableName: "osm",
 35→    autoLoadLayers: {
 36→      coordinateFormat: "EPSG:3395",
 37→      layers: ["surface", "parks", "water", "roads"],
 38→      dropOsmTable: true,
 39→    },
 40→    onProgress: (phase: string) => {
 41→      setPhase(`OSM: ${phase}`);
 42→      console.log(`Overpass progress: ${phase}`);
 43→    },
 44→  });
 45→
 46→  console.log("OSM data loaded successfully");
 47→
 48→  const layerTables = db.getLayerTables();
 49→  console.log(
 50→    `Loaded ${layerTables.length} OSM layers:`,
 51→    layerTables.map((l) => l.name)
 52→  );
 53→
 54→  // ── 4. Get roads GeoJSON for GPU length computation ──
 55→  setPhase("Computing road segment lengths on GPU...");
 56→  console.log("Retrieving roads layer for GPU computation...");
 57→  const roadsGeojson = await db.getLayer("osm_roads");
 58→  console.log(`Roads loaded: ${roadsGeojson.features.length} features`);
 59→
 60→  // ── 5. Prepare road geometry for GPU computation ──
 61→  console.log("Preparing road geometry for GPU shader...");
 62→
 63→  let maxCoords = 0;
 64→  for (const feature of roadsGeojson.features) {
 65→    const geom = feature.geometry;
 66→    if (geom.type === "LineString") {
 67→      maxCoords = Math.max(maxCoords, geom.coordinates.length);
 68→    } else if (geom.type === "MultiLineString") {
 69→      let total = 0;
 70→      for (const line of geom.coordinates) {
 71→        total += line.length;
 72→      }
 73→      maxCoords = Math.max(maxCoords, total);
 74→    }
 75→  }
 76→
 77→  console.log(`Max coordinate points per road segment: ${maxCoords}`);
 78→
 79→  // Add flattened coordinate arrays to properties for GPU access
 80→  for (const feature of roadsGeojson.features) {
 81→    const geom = feature.geometry;
 82→    const xs: number[] = [];
 83→    const ys: number[] = [];
 84→
 85→    if (geom.type === "LineString") {
 86→      for (const coord of geom.coordinates) {
 87→        xs.push(coord[0]);
 88→        ys.push(coord[1]);
 89→      }
 90→    } else if (geom.type === "MultiLineString") {
 91→      for (const line of geom.coordinates) {
 92→        for (const coord of line) {
 93→          xs.push(coord[0]);
 94→          ys.push(coord[1]);
 95→        }
 96→      }
 97→    }
 98→
 99→    if (!feature.properties) feature.properties = {};
100→    feature.properties.coords_x = xs;
101→    feature.properties.coords_y = ys;
102→    feature.properties.num_coords = xs.length;
103→  }
104→
105→  console.log("Geometry prepared, dispatching to GPU...");
106→
107→  // ── 6. Compute road segment lengths on GPU using shader ──
108→  const roadsWithLength = await gpuCompute.computeFunctionIntoProperties({
109→    geojson: roadsGeojson,
110→    attributes: {
111→      coords_x: "properties.coords_x",
112→      coords_y: "properties.coords_y",
113→      num_coords: "properties.num_coords",
114→    },
115→    attributeArrays: {
116→      coords_x: maxCoords,
117→      coords_y: maxCoords,
118→    },
119→    outputColumnName: "segment_length",
120→    wglsFunction: `
121→      var total_length = 0.0;
122→      let n = u32(num_coords);
123→      for (var i = 1u; i < n; i++) {
124→        let dx = coords_x[i] - coords_x[i - 1u];
125→        let dy = coords_y[i] - coords_y[i - 1u];
126→        total_length += sqrt(dx * dx + dy * dy);
127→      }
128→      return total_length;
129→    `,
130→  });
131→
132→  console.log("GPU computation complete — road segment lengths calculated");
133→
134→  // Log some stats
135→  const lengths = roadsWithLength.features.map(
136→    (f: Feature) => (f.properties?.compute?.segment_length ?? 0) as number
137→  );
138→  const maxLength = Math.max(...lengths);
139→  const avgLength =
140→    lengths.reduce((a: number, b: number) => a + b, 0) / lengths.length;
141→  console.log(
142→    `Road length stats — max: ${maxLength.toFixed(2)}m, avg: ${avgLength.toFixed(2)}m`
143→  );
144→
145→  // ── 7. Update database with computed lengths ──
146→  setPhase("Updating database with computed lengths...");
147→  console.log("Writing computed lengths back to database...");
148→
149→  await db.updateTable({
150→    tableName: "osm_roads",
151→    data: roadsWithLength,
152→    strategy: "replace",
153→  });
154→
155→  const updatedRoads = await db.getLayer("osm_roads");
156→  console.log("Database updated with road segment lengths");
157→
158→  // ── 8. Initialize map renderer ──
159→  setPhase("Initializing map renderer...");
160→  console.log("Initializing AutkMap...");
161→
162→  const map = new AutkMap(canvas);
163→  await map.init();
164→  console.log("AutkMap initialized");
165→
166→  // ── 9. Load all OSM layers onto the map ──
167→  setPhase("Loading layers onto map...");
168→
169→  const layerTypeMap: Record<string, LayerType> = {
170→    osm_surface: LayerType.AUTK_OSM_SURFACE,
171→    osm_parks: LayerType.AUTK_OSM_PARKS,
172→    osm_water: LayerType.AUTK_OSM_WATER,
173→    osm_roads: LayerType.AUTK_OSM_ROADS,
174→  };
175→
176→  for (const layer of layerTables) {
177→    const geojson =
178→      layer.name === "osm_roads"
179→        ? updatedRoads
180→        : await db.getLayer(layer.name);
181→    const type = layerTypeMap[layer.name] ?? (layer.type as LayerType);
182→    map.loadGeoJsonLayer(layer.name, geojson, type);
183→    console.log(
184→      `Layer "${layer.name}" loaded (${geojson.features.length} features)`
185→    );
186→  }
187→
188→  console.log(`Scene rendered with ${layerTables.length} layers`);
189→
190→  // ── 10. Apply thematic coloring to roads by segment length ──
191→  setPhase("Applying road length coloring...");
192→  console.log("Applying thematic coloring based on road segment length...");
