## 9. Complete End-to-End Example

```typescript
import { SpatialDb } from 'autk-db';
import { AutkMap, LayerType, MapEvent, ColorMapInterpolator } from 'autk-map';

async function main() {
  // 1. Initialize DB
  const db = new SpatialDb();
  await db.init();

  // 2. Load OSM data
  await db.loadOsmFromOverpassApi({
    queryArea: { geocodeArea: 'New York', areas: ['Manhattan Island'] },
    outputTableName: 'osm',
    autoLoadLayers: {
      coordinateFormat: 'EPSG:3395',
      layers: ['surface', 'parks', 'water', 'roads', 'buildings'],
      dropOsmTable: true,
    },
  });

  // 3. Load CSV data
  await db.loadCsv({
    csvFileUrl: '/data/subway_stations.csv',
    outputTableName: 'subway_stations',
    geometryColumns: {
      latColumnName: 'latitude',
      longColumnName: 'longitude',
      coordinateFormat: 'EPSG:3395',
    },
  });

  // 4. Spatial join
  await db.spatialJoin({
    tableRootName: 'osm_buildings',
    tableJoinName: 'subway_stations',
    output: { type: 'MODIFY_ROOT' },
    spatialPredicate: 'NEAR',
    nearDistance: 500,
    joinType: 'LEFT',
    groupBy: {
      selectColumns: [{
        tableName: 'subway_stations',
        column: 'id',
        aggregateFn: 'count',
        aggregateFnResultColumnName: 'subway_count',
        normalize: true,
      }],
    },
  });

  // 5. Initialize map
  const canvas = document.getElementById('map-canvas') as HTMLCanvasElement;
  const map = new AutkMap(canvas);
  await map.init();

  // 6. Load layers
  for (const layer of db.getLayerTables()) {
    const geojson = await db.getLayer(layer.name);
    map.loadGeoJsonLayer(layer.name, geojson, layer.type as LayerType);
  }

  // 7. Apply thematic coloring to buildings
  const buildingsGeoJson = await db.getLayer('osm_buildings');
  map.updateRenderInfoProperty('osm_buildings', 'colorMapInterpolator', 
    ColorMapInterpolator.SEQUENTIAL_REDS);
  map.updateRenderInfoProperty('osm_buildings', 'isColorMap', true);
  map.updateGeoJsonLayerThematic(
    'osm_buildings',
    buildingsGeoJson,
    (f) => f.properties?.sjoin?.count?.subway_count_norm ?? 0,
    true
  );

  // 8. Enable picking
  map.updateRenderInfoProperty('osm_buildings', 'isPick', true);
  map.mapEvents.on(MapEvent.PICK, (selectedIds, layerId) => {
    console.log(`Selected on ${layerId}:`, selectedIds);
  });

  // 9. Start rendering
  map.draw();
}

main();
```

